  ('judicial-7acda994-moex-00152', 'judicial-7acda994', 'judicial-7acda994-moex-110-0835bf52', 'sub-judicial-7acda994-04', NULL, 'essay', '依漁業動力用油優惠油價標準之規定，漁業人有將申購之優惠漁船油用
於從事非漁業行為者，應繳回該違規航次漁業動力用油量之優惠油價補
貼款。據此，某甲的漁船受有行政機關給付之優惠油價補貼款，嗣後被
查獲從事非漁業行為，行政機關以「函文通知」某甲依法應繳回補貼款。
上述行政機關「函文通知」之性質為何？又決定其性質對於向某甲請求
繳回補貼款之途徑有何差別？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:31+00:00", "source_pdf_sha1": "71b3edf3fb46", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "104", "s": "0309", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政程序法與行政執行法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "行政執行官"}'::jsonb, NULL),
